INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老五星酒店，但是出乎预料的惊喜，大堂很大气，环境很好，交通便利，对面就是广州酒家', '老五星酒店，但是出乎预料的惊喜，大堂很大气，环境很好，交通便利，对面就是广州酒家。荔湾亭的茶点很好吃??以后来广州还会选择花园酒家', '2025-03-19', 5, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236e12000j5xvpisBCEF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000j5x92zt724D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住体验非常好。因为看到早餐能选三家餐厅订了这家酒店，入住三天把三家餐厅都体验了', '入住体验非常好。因为看到早餐能选三家餐厅订了这家酒店，入住三天把三家餐厅都体验了一下，味道非常好（就是高峰期可能要排队，不过很快就排到了）。虽然是老酒店，但是房间里的装修、设施都很新，性价比很高。', '2025-01-31', 5, '[''餐饮设施'', ''房间设施'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0232w12000i6srp5cD0EA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000i6sczy0F448_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233712000i6rf0h98DF1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '有名气的老酒店，但是维护保养的很不错，感觉也非常热闹入住人员挺多，所以房间没打扫', '有名气的老酒店，但是维护保养的很不错，感觉也非常热闹入住人员挺多，所以房间没打扫空出的时候，前台小哥哥及时的升级安排房间，为宾客解决问题的能力点赞。酒店大堂富丽堂皇，还有自己的博物馆而且还规模不小，空闲时参观一下还是非常有意义的。花园酒店为这次的广州行添色不少。', '2025-01-22', 5, '[''前台服务'', ''整体满意度'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234u12000hzvgmbsB26E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000hzueid1A73A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000hzv7w0v3AE7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000hzup90gF322_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000hzvzajq0486_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000hzuwpidF94F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州老牌的五星酒店，各方面都很满意。早餐体验了桃园馆和30楼的旋转餐厅，小朋友很', '广州老牌的五星酒店，各方面都很满意。早餐体验了桃园馆和30楼的旋转餐厅，小朋友很开心，家庭旅行的首选！', '2025-04-06', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233o12000jlj9v9jC401_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000jlimaso8719_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000jljiawp2BF3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000jljk76sD6D0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000jljgxd4D923_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节人流大，入住时间比较长，主动升级了房型，很舒适。整体感觉不错，服务效率高，体', '春节人流大，入住时间比较长，主动升级了房型，很舒适。整体感觉不错，服务效率高，体验了瀑布餐厅和旋转餐厅，环境不错，菜品感觉一般。酒店花园很美，博物馆也很用心，总归是很有特色，可以再来。', '2025-02-04', 5, '[''整体满意度'', ''餐饮设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235m12000iassmr4A100_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236y12000iast3nk42EA_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233x12000iasvio2C328_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带家人前往广州旅游，选择下榻广州花园酒店两晚，二楼餐厅荔湾亭跟三楼的粤菜餐厅出品', '带家人前往广州旅游，选择下榻广州花园酒店两晚，二楼餐厅荔湾亭跟三楼的粤菜餐厅出品菜品水准都是ok的，推荐体验！另外六小龄童经理不错，满分好评！', '2025-03-21', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231o12000j8d5zkaF60B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000j8dkyh7DBCB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间不错 虽然年代感强一些 但是还是挺干净的。前台服务人员也很贴心 我们到的晚 ', '房间不错 虽然年代感强一些 但是还是挺干净的。前台服务人员也很贴心 我们到的晚 订的房型没有了 直接安排了升级房型。舟车劳顿后的关心真让人感动呀。早餐的餐厅环境不错 听着瀑布声吃早餐感觉很放空 ?值得再次体验', '2025-01-21', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0232w12000hyj2rty1453_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '定了两间房，给妈妈的大床房升级成了套房，她很满意，我和孩子住的双床房一般，尤其是', '定了两间房，给妈妈的大床房升级成了套房，她很满意，我和孩子住的双床房一般，尤其是卫生间和浴缸共用一个推拉门这个设计着实有些减分。我想很多选择花园酒店的顾客多半是有些情怀的，毕竟曾经也是名气在线的。酒店的优势:位置好，出门是地铁，对面是商场，附近小吃多，广州酒家，点都德都在200米以内的范围。酒店有博物馆和花园，很赞，而且酒店博物馆的纪念品价格并不比外面高，这点很难得。酒店的不足:进门的服务很糟糕，我们大包小包的行李视若不见，而我一转身，后面的老外的行李，服务人员就笑脸相迎上去了，呵呵呵，什么年代了！！办理入住的队伍排很长，周边没有可以休息的座位，无奈，先存行李回来再次办理，问行李寄存处在哪里，手一挥，鬼知道你指的哪里！办理入住的前台小姐姐问一句，答一句，多说一个字像要收费似的，酒店里有博物馆和花园也不主动告知，还是旁边路过的阿姨告诉我们的！果断后两天转住了文华东方。除了入住前的不快，其余的时候都挺满意，心理觉得有些遗憾，以后不会选择这家了。五星酒店广州从来都不缺。', '2025-01-23', 4, '[''前台服务'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233412000i0m2kqmB029_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000i0mruckD5FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000i0mnn8h822A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000i0mokxwFD01_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000i0mycr81B8B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000i0mp35pCD8E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000i0lxo5x83DE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000i0md1htE054_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净宽敞，因为是会员的关系还免费升级了房间和使用行政酒廊。出行也很方便，时间', '房间干净宽敞，因为是会员的关系还免费升级了房间和使用行政酒廊。出行也很方便，时间关系没有打卡酒店餐厅，据说有很多推荐好餐厅，下次有机会再试吧。', '2025-04-03', 4, '[''房间设施'', ''整体满意度'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236912000jiiab7q5FB2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000jihu00lFD3E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000jigwvsfF72B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务意识不是很强，经常会没人帮着推门，办理行李寄存的时候小哥在接打电话，可以理解', '服务意识不是很强，经常会没人帮着推门，办理行李寄存的时候小哥在接打电话，可以理解比较忙，但是也没有给客户打招呼表示歉意，旁边的工作人员看着我们傻等着也没有接手的意思，整体的体验感比较一般', '2025-03-04', 4, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234112000ivcqmaa8219_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000ivcabxs1960_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000ivbuwe62727_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店是一家老牌酒店，在市中心地段，地铁淘金站A口出地面只要走两分钟就到了', '广州花园酒店是一家老牌酒店，在市中心地段，地铁淘金站A口出地面只要走两分钟就到了酒店大堂。酒店服务周到，我们要求送的瓶装水浴巾拖鞋碘伏棉签创可贴也很快送到。酒店周围环境也很美，吃饭很方便。房间设施虽然有点旧，但很干净，唯一不太合理的就是灯光分组。', '2025-01-18', 5, '[''交通便利性'', ''客房服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230s12000hw06jjnCA5E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000hvzijga6D8B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000hvzygtlAA87_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '蛮好的老牌酒店，交通便利，旁边有地铁站，停车疗仨人。春节很繁忙，管理也到位，房间', '蛮好的老牌酒店，交通便利，旁边有地铁站，停车疗仨人。春节很繁忙，管理也到位，房间卫生干净，早歺歺厅选择范围多，桃花馆歺厅味道佳，退房退押金快速。', '2025-02-04', 5, '[''交通便利性'', ''卫生状况'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0234j12000iafsxhx8753_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230t12000iaf849vD485_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000iafoh9bFA53_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000iafggll77E2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000iaflp7pC00C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000iaf3n000B40_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000iafljzt78E4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000iafot9gA5D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000iafvr6gFB2D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店地理位置优越，设施齐全，房屋整洁。酒店所有工作人员的服务都非常周到，尤其Wi', '酒店地理位置优越，设施齐全，房屋整洁。酒店所有工作人员的服务都非常周到，尤其Winnie  wei很贴心，有求必应。有欢迎花束，还非常幸运地升级了房型。早上在旋转餐厅边吃饭边欣赏美景。偶然间选择的这个酒店，很满意！', '2025-01-21', 5, '[''整体满意度'', ''前台服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233c12000hynzyizC307_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000hyo4g8005C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000hyo9v6aC5B6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一如既往的好，尤其是春节期间，特别热闹又有年味。服务比多家五星级酒店更好，出街期', '一如既往的好，尤其是春节期间，特别热闹又有年味。服务比多家五星级酒店更好，出街期间除了大堂有各种活动和集市以外，每一层都有一位工作人员帮忙按电梯，在过年期间，服务做到这个程度非常难得！', '2025-01-30', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234a12000i62cy3o7067_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233n12000i62dpj9238B_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236y12000i62dr6tBA6D_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带爸妈去广州，住的花园酒店粤韵套房。入住期间正逢妈妈生日，酒店赠送了蛋糕，让我们', '带爸妈去广州，住的花园酒店粤韵套房。入住期间正逢妈妈生日，酒店赠送了蛋糕，让我们宾至如归。二楼荔湾亭的东西也很好吃，我们那桌的服务员是位阿姨，很耐心，介绍的菜品也很得我们喜欢（忘记问姓名了）特此感谢。另外表扬前台Betty，12楼客服谢现涛，对我们无微不至的关怀和照顾。', '2025-02-14', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234n12000iizc1swAC19_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234h12000iizbntv2F81_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235b12000iizc3vx3586_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230612000iizc6gj40D5_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '来广州一定要争取住花园酒店！雍容华贵，是中国三家白金五星酒店之一。特别感谢前台服', '来广州一定要争取住花园酒店！雍容华贵，是中国三家白金五星酒店之一。特别感谢前台服务员，给我们把房间升级了！让我们更加不虚此行！', '2025-03-27', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235e12000jcrhg0tB3E8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000jct2n0q3F7E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231c12000jcroc2d3E46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000jcsz4cu4C9E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '费了半天口舌 那个岭汇峰金卡（好像是这个名吧 记不住了）终于派上用途给升了房型 ', '费了半天口舌 那个岭汇峰金卡（好像是这个名吧 记不住了）终于派上用途给升了房型 红棉房还是真不错的 面积很大 客房很新 服务也算热情 酒店人巨多 好像是商务开会聚集地 定了三晚 只送了一个早餐卷 也没用上 每次路过都是站排 总体还是推荐的 附长隆动物图', '2025-01-20', 5, '[''房间设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230612000hx33k365A89_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000hx0lye8FC18_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000hx2xk5j0E2C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000hx336if92DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230o12000hx0povy502A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000hx1kfla504A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000hx20rgc5315_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o12000hx30w2i6B39_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000hx1dsdtDB44_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务：酒店的服务让人印象深刻，春节期间非常敬业。 行政酒廊，大堂的礼宾，公寓客房', '服务：酒店的服务让人印象深刻，春节期间非常敬业。 行政酒廊，大堂的礼宾，公寓客房的服务都令人满意。

春节期间的布置，有节日的气氛。酒店内行政酒廊进去有个很大的后花园，还有瀑布。', '2025-02-02', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230c12000i8jbcsx42CA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000i8i1kod6C07_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235i12000i8jlajs622A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000i8i0by0F0AE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000i8joptoD7CF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '住过的酒店不少，但离开后希望还有机会再次入住的酒店却很少。广州花园酒店是这很少之', '住过的酒店不少，但离开后希望还有机会再次入住的酒店却很少。广州花园酒店是这很少之一。这次带了家里老人出行，选择入住花园酒店，优良的设施，便利的交通，白金五星的服务也让家人度过了非常愉快的假日。酒店自带的博物馆和有瀑布的中庭花园让我们很是惊喜，行政酒廊的出品和服务更让人印象深刻，在此特别感谢酒廊的Carrie、Mira、Berryle专业周到的服务，虽是短暂停逗，却令我们感觉如沐春风，宾至如归。', '2024-11-25', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230b12000gusr0hi1106_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236912000guthx6dE7A3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000gus4srx62C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000gutmk1y06E4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000gusl87pAA89_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000guscemi1638_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000gus7qvtDBB7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000gusfvb74B65_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000gutip9zD8D6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务非常满意，特别前台小姐姐给升级一房一厅客房啦??心情愉悦。这个老牌五星级酒店', '服务非常满意，特别前台小姐姐给升级一房一厅客房啦??心情愉悦。这个老牌五星级酒店我在30年前来过，现在旧地重游还是感觉非常满意！特别是它家的后花园假山瀑布，绿色植物荷塘月色景致一流心旷神怡。这次我们房费还包括了行政酒廊欢乐时光，使用下来感觉质量非常满意，厨师水平比一般的五星级酒店高，精致味道超级好，特别有二个选项菜单，点的菜是米其林出品啊??前台后面的背景一如40年前大气豪华，有特色的原木旋转楼梯及二楼古色古香摆品都体现精致豪华。早餐还开放了30楼的旋转餐厅。这是一次完美的体验。', '2025-01-18', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/02342224x8ypjdbitCB74_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02310224x8ypklpzm5050_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02353224x8yplglzrFB19_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l224x8ypmmqqv04EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02344224x8yplglzsD528_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230o224x8ypji0cmDFED_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一家三口，由于工作关系四晚住了亚朵（五羊邨店2晚，太古汇2晚）只能说性价比非常低', '一家三口，由于工作关系四晚住了亚朵（五羊邨店2晚，太古汇2晚）只能说性价比非常低，爸爸果断选择了换花园，交通方便，吃住便利，环境怡人，订房文旅送了优惠券1间200元/每晚。只能说选花园红棉房太对了。和前台沟通带孩子避开头尾，安排的非常好呀。真是太满意了。虽没有早餐，但是酒店背后去吃了点都德早茶（超级近），还是得在本地点都德吃，非常好，孩子也高兴满意。', '2025-02-02', 5, '[''性价比'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232v12000i921ngu398F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000i91bc9n288F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236512000i91wfez868E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000i90po2b9B50_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000i91kgh93446_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000i8zznha84D4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000i91h4zeD2F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000i91x52jE908_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230m12000i91xv8v3A57_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '本地人第一次入住，体验不错，无论是大堂的装潢、香氛，还是房间的布局、设施都给我高', '本地人第一次入住，体验不错，无论是大堂的装潢、香氛，还是房间的布局、设施都给我高级的感觉，入住第一感觉是卫生可靠。环境很安静。', '2025-03-21', 5, '[''整体满意度'', ''安静程度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235v12000j85imwoB613_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000j85g4ja1D78_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000j84mztvE035_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境：后花园很气派，还有瀑布，小桥流水很优美', '环境：后花园很气派，还有瀑布，小桥流水很优美
设施：房间内设施有些陈旧了，达不到金五星
服务：前台礼貌热情，但预订的早餐不可退属于强卖，自助早餐非常不值人均200，要避坑', '2025-02-19', 3, '[''公共设施'', ''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000img0exnA811_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000img9rwj87CE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233i12000imfysid22A5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间酒店贴心服务，帮我们升级为套房，处处为客户着想，服务员微笑服务，打扫房间及时', '房间酒店贴心服务，帮我们升级为套房，处处为客户着想，服务员微笑服务，打扫房间及时，酒店环境舒适温馨高雅。', '2025-03-27', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235o12000jct72xwC38B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000jcsil4cFFBA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很好??！服务好，工作人员很耐心细致！不愧为五星级国际酒店！桃园馆定制早茶也有广', '很好??！服务好，工作人员很耐心细致！不愧为五星级国际酒店！桃园馆定制早茶也有广式特色！特别是蛋塔很有风味！前台可以寄存物品。酒店管理很有秩序，很安全！真心觉得祖国很安全！', '2025-02-02', 5, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230y12000i8ykbpp6B27_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000i8ywnz8D241_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000i8y2puw99DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000i8ynjyv98E6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '住了七八次了，这次房间出了一点小小的问题。刘经理和麦经理先后帮我们细心处理，周到', '住了七八次了，这次房间出了一点小小的问题。刘经理和麦经理先后帮我们细心处理，周到解决，都让我们感到非常不好意思了。所以，每次都是广州的入住首选。也在这里对两位巡房经理表示衷心的感谢！', '2025-02-08', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232s12000ie59s3g5441_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '选择花园酒店是一个意外惊喜。', '选择花园酒店是一个意外惊喜。
家人鼻子敏感 一直以来特别抗拒老旧酒店，主要是受不了沉积在排气管道、装饰里面的陈腐味道，比较偏向于选择5年内的新酒店。
被酒店的评论区以及多个米其林餐厅吸引，于是决定试试。进入酒店后，酒店浓浓的历史感经过岁月的沉淀以及酒店的用心维护，感受到的是古典、优雅、大气，更加惊喜的是它居然是剧院魅影的官方合作酒店，大堂中央放着经典的白色面具！可把孩子高兴坏了，我们大老远来就是来二刷魅影！这是一个意外的大彩蛋，好感度已经拉满。
另外一个惊喜是入住时，安排的低楼层接近装修项目，向酒店反映噪音问题后，马上进行了调整甚至升房，效率和服务很赞。因为孩子身体不适，延迟退房申请也安排得妥妥的，非常感谢！
套餐含夜茶任点，出品优秀，都是很经典的广府点心，推荐(＾ω＾)????', '2025-01-12', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000hqf8r0p80DD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233s12000hqf3htc60B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000hqfm21717AB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店本身就是一个景点，很有设计感，酒店本身带有一个博物馆，很值得参观一下，就是人', '酒店本身就是一个景点，很有设计感，酒店本身带有一个博物馆，很值得参观一下，就是人太多太杂，酒店的客房设施比较陈旧，而且设计有点不太合理，房间私密性不够，由于酒店周边在施工，有点噪音，不够安静，前台员工的服务意识有待提升，可能太忙的关系，全程都没笑脸，对于相关的酒店待遇没有主动介绍，还是客人自己提醒下才给予，感觉有点不太好，相比行政酒廊的员工就热情很多', '2025-01-14', 4, '[''房间设施'', ''安静程度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232a12000hs3f2naF521_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000hs33izl8D0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000hs3b95u0CC2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '闹市宝藏店，环境资源独具一格。居住品质好，一如广州这座城市特有的包容温润，早餐极', '闹市宝藏店，环境资源独具一格。居住品质好，一如广州这座城市特有的包容温润，早餐极好，氛围感拉满，值得续住。', '2025-03-23', 4, '[''餐饮设施'', ''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0233y12000j9ejr0k7D25_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000j9enxsqF3C4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000j9e3teaA196_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235c12000j9dzkgz5783_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231i12000j9er1bbE462_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000j9e8o4vB060_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店有非常多的餐厅，中西餐厅日式餐厅都有，特别是有一个网红瀑布餐厅比较出名，很多', '酒店有非常多的餐厅，中西餐厅日式餐厅都有，特别是有一个网红瀑布餐厅比较出名，很多人来到打卡，在酒店内就能够满足用餐需求。感谢前台Viria的介绍以及服务周到，给予好评！', '2025-03-31', 5, '[''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233n12000jg0r2pdEA60_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000jg0m34zA5FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000jg0aqmn710B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店过年活动多，氛围很浓，一到酒店感觉很欢乐。房间很舒适，配有胶囊咖啡机，服务不', '酒店过年活动多，氛围很浓，一到酒店感觉很欢乐。房间很舒适，配有胶囊咖啡机，服务不错。一楼后面小花园修的很漂亮。只是设施稍显老旧，淋浴间漏水到隔壁马桶间，需要注意及时维修。', '2025-02-01', 4, '[''房间设施'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235l12000i7zd6qk9D6C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000i7zd6qm5509_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000i7y6nh9C4A2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230a12000i7zd6qoD38E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店服务很好！餐厅特别棒！早餐非常好！花园和博物馆也可以看看。门口就可以直接坐出', '酒店服务很好！餐厅特别棒！早餐非常好！花园和博物馆也可以看看。门口就可以直接坐出租车，非常便捷。因为楼设计合理，电梯也不拥挤。体验很好。唯一就是房间小。房间太小。', '2025-02-04', 5, '[''餐饮设施'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233u12000iakqx5t5791_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z12000iake0i4FEDB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000iakaycd9956_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000iakaycf381F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000iajunuz864A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000iak5o3948A8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000iakv23m03CB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000iajwj121A1F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000iakk8gvCB67_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很有年代感，依然记得小时候第一次在花园酒店咖啡厅感受到的宏伟。酒店服务人员还', '房间很有年代感，依然记得小时候第一次在花园酒店咖啡厅感受到的宏伟。酒店服务人员还蛮热情。', '2025-04-05', 4, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000jkhiika18F7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一分钱一分货，这么老的酒店还是不错了，谢谢前台给我房间升级为套房，楼下花园还是很', '一分钱一分货，这么老的酒店还是不错了，谢谢前台给我房间升级为套房，楼下花园还是很不错的，特别是瀑布。', '2025-03-27', 5, '[''整体满意度'', ''前台服务'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0235r12000jcxo47zE671_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236n12000jcxo481FECA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000jcxrt549BF0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '春节带家里老小体验老牌的五星级酒店，环境服务都很好，过年的气氛也很浓，小朋友在花', '春节带家里老小体验老牌的五星级酒店，环境服务都很好，过年的气氛也很浓，小朋友在花园里玩了很久，感谢前台ANN，服务态度非常好，还免费加赠了早餐，很美好的体验！', '2025-02-05', 5, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232p12000ible13c4461_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000ibkzuklE21D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000ibl645v4D8B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000ibl6tijBEF0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店环境好，整洁干净，入住时前台升级了房间，服务人员热情周到，每天还送水果，', '花园酒店环境好，整洁干净，入住时前台升级了房间，服务人员热情周到，每天还送水果，下次来还住花园酒店。', '2025-03-23', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234h12000j9k6slq01C6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000j9k7kbh69AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000j9jdwc0D173_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231t12000j9k6z3t18F1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000j9k33vr338B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000j9j37haCFE8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000j9k4ruv5BD6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '孩子不舒服，不小心吐在了床单上，服务人员耐心打扫，非常专业。酒店环境非常好，室内', '孩子不舒服，不小心吐在了床单上，服务人员耐心打扫，非常专业。酒店环境非常好，室内座椅有些老化。忘了东西在酒店，酒店及时联系并帮忙寄回。非常感谢！', '2025-02-19', 5, '[''客房服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231y12000imcmrlq1EED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000imc1gn8FD13_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237112000imc8n7r61E5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '到酒店后前台把我的红棉房升级到了粤韵房，窗口正对着对面的白云宾馆的街口，酒店服务', '到酒店后前台把我的红棉房升级到了粤韵房，窗口正对着对面的白云宾馆的街口，酒店服务很好不愧是白金五星酒店，早晨早餐高峰和中午退房高峰时各楼层电梯口会安排服务生招呼客人，住过无数个酒店还是第一次看到这样的服务。
楼下就是地铁淘金站，外国住客多。免费参观酒店博物馆，整整在里面徜徉了45分钟，能看到很多东西，愿意拿出一个楼面做丝毫没有收益的博物馆，真壕。', '2025-01-08', 4, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230l12000hnwl7jc7913_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000hnx172a8B65_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234c12000hnwx0fe9C3B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000hnxbrhlC9CA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000hnw9zvrDD38_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000hnxbmjx8933_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000hnw4m7sABA8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间面积不大，环境很棒，大堂非常漂亮，服务人员都特别好，有1个插座用不了，设施稍', '房间面积不大，环境很棒，大堂非常漂亮，服务人员都特别好，有1个插座用不了，设施稍微老一些，地理位置很优越，出行非常方便，三楼早餐特别好吃', '2025-02-19', 4, '[''交通便利性'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232b12000ilzyobcBB3B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园房很小，进门就是一个浴缸，比较老式的风格，前台接待的服务很一般，携程的岭南客', '花园房很小，进门就是一个浴缸，比较老式的风格，前台接待的服务很一般，携程的岭南客金卡有一份免费早餐，也是我自己问的，都不主动提起，入住收1000元押金，现在也不多见了。迷你吧都要收费。住的是一个情怀吧。下次不会再选择了。早餐也很一般。位置在中心。出门打车都很方便', '2025-01-02', 3, '[''房间设施'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0236s12000hjj3calEACD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000hjjaq602699_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233g12000hjit0xxBB98_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000hjiyhhh075A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是国内唯三的白金五星酒店，漂亮的瀑布花园，舒适的床品，优质的服务，改革开放历', '不愧是国内唯三的白金五星酒店，漂亮的瀑布花园，舒适的床品，优质的服务，改革开放历史见证，广州花园酒店值得再次入住。', '2025-03-05', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233v12000ivvkbi38D97_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232g12000ivwc2xm8027_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234x12000ivvv2wa8F6E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000ivw5x8aD338_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000ivvqw8102A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000ivw0ehqF77D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次入住酒店，有幸遇见前台KIKI XU笑脸相迎，安排了舒适的房间，能遇见您，让', '这次入住酒店，有幸遇见前台KIKI XU笑脸相迎，安排了舒适的房间，能遇见您，让我们的旅途变得更加美好。
        酒店在市中心，门口就是地铁站，去任何地方玩都很方便。
        酒店本身就是一个景点，有26个地方可以打卡，后花园很漂亮，不仅有水景假山，还挂着2条18米高的瀑布，4楼还有一个博物馆，住在这里有种世外桃源的感觉。
        祝酒店生意兴隆。', '2024-12-16', 5, '[''前台服务'', ''交通便利性'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233z12000h8buq6h138A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000h8bj1q4E577_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000h8c0agpC5A5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000h8cb71x288C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234o12000h8bsyn9A5F2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000h8bqa8zC251_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000h8cd3qd1380_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237412000h8c4sr1A00F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231z12000h8bfrdwF02A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净卫生，服务员态度很好，涉外酒店，入住客人多，早餐需要排队，但是用餐环境很', '房间干净卫生，服务员态度很好，涉外酒店，入住客人多，早餐需要排队，但是用餐环境很好，顶楼还有旋转餐厅，可以边吃边欣赏城市景色，早饭品种很多，味道很棒！还有一个大花园，有瀑布，有金鱼，逛逛，大饱眼福。唯一不足房间有点小。', '2025-03-26', 5, '[''卫生状况'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230h12000jc5oh5l3F35_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000jc4roznCC8F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000jc5geev6CFF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置很优越，就在地铁站旁边，去哪里都方便，马路对面的广州酒家菜品很好吃，酒店最出', '位置很优越，就在地铁站旁边，去哪里都方便，马路对面的广州酒家菜品很好吃，酒店最出彩的是后花园，有山有水，树木茂盛，在里面悠闲惬意。早餐还是蛮丰富的，桃源阁的是广州特色定食，但得事先预约，用餐环境舒适。大堂金碧辉煌有点嘈杂', '2025-01-02', 4, '[''交通便利性'', ''周边配套'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232112000hjlchllB91D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h12000hjkrlctDF5D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000hjlq0au9FFB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000hjld5048C23_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000hjln5gnC37E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店外观很大，感觉很气派，所以选择入住，但是房间还是比较老旧的，差点意思，和现在', '酒店外观很大，感觉很气派，所以选择入住，但是房间还是比较老旧的，差点意思，和现在新酒店相比还是新的酒店科技发达，关键充电地方多，这里还是老式的充电头，关键晚上的夜茶是真难吃，还有就是我想吐槽的，我老公证件忘记在房间，退房了两天既然也没有人和我联系，后来去机场发现没有了，又每个酒店去找，找到这里才给我们，说是疏忽了，难道这种重要的东西发现了不是这时间联系顾客的吗', '2025-01-05', 4, '[''前台服务'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233e12000hldch6s0A26_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000hlciwhr9A5E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000hld2x190BE5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000hld2x1bC406_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000hldaovhC58E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很安静，设施齐全，送餐服务及时周到，下午可以在花园散步，很适合放空', '房间很安静，设施齐全，送餐服务及时周到，下午可以在花园散步，很适合放空', '2025-04-11', 5, '[''安静程度'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230g12000jq3fmfp5ADD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000jq357w77697_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000jq4bb259C40_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '带有博物馆的老牌酒店，有自己的文化底蕴，值得过来感受一下，据广州当地的朋友说酒店', '带有博物馆的老牌酒店，有自己的文化底蕴，值得过来感受一下，据广州当地的朋友说酒店内的早茶是天花板级别的，作为东北人体验了一下，倒也没吃出来太特别的！', '2025-02-02', 4, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231612000i8p9623CD24_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234612000i8pyf3b3D4A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000i8pwlkh26FE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000i8os0st0009_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间舒适，设备比想象的要新很多，服务团队非常热情而且专业。特别给Tina点赞', '房间舒适，设备比想象的要新很多，服务团队非常热情而且专业。特别给Tina点赞', '2025-04-07', 5, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230212000jmpynah48B1_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置特别好，去哪里都方便。后面的小胡同还有很多好吃的小店。打车基本都是5分钟内到', '位置特别好，去哪里都方便。后面的小胡同还有很多好吃的小店。打车基本都是5分钟内到达，大堂很气派，礼宾部的服务也很好，整体都很不错，下次来广州还会住这里。', '2025-01-28', 4, '[''交通便利性'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0230k12000i4c3xztF6DE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235312000i4cp5m03EA3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000i4cd65pCE19_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间非常满意，交通很便利，出门就是地铁站。酒店大堂很辉煌很大气！前台VIRIA服', '房间非常满意，交通很便利，出门就是地铁站。酒店大堂很辉煌很大气！前台VIRIA服务非常好！', '2025-03-21', 5, '[''交通便利性'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231n12000j7wawjqEC58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000j7wp2gbBB8F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000j7voqorD6AA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '期待的广州花园酒店没有让我们失望', '期待的广州花园酒店没有让我们失望
一进大堂就感受到大气，真金剪纸壁画显示了红楼梦的故事情节，流程和导引非常高效，办理入住的小丘非常专业和亲切，作为金卡会员不但给了升级还体贴地赠送了小朋友的早餐！非常感动！房间也非常舒适，门口就有地铁站 下次来一定还住这里', '2025-02-04', 5, '[''前台服务'', ''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231512000iar8c4n5AFD_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233u12000iar7h2x0352_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232q12000iar6fufDA16_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234z12000iar7slx56C0_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232312000iar7h39FE71_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234n12000iar8evb65C7_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232g12000iar7cmxBF0D_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这个酒店最难受的是开放式卫生间。洗澡间和卫生间共用一个推拉门；然后与床之间也是一', '这个酒店最难受的是开放式卫生间。洗澡间和卫生间共用一个推拉门；然后与床之间也是一个半玻璃门隔开的。俩人入住，一个人洗澡，另一个人最上卫生间就是敞开式，真是不方便。
     我们的房间外面有个大工地，似乎是在修地铁，工地的噪声夜里还是听的听清楚的。
   不过酒店的工作人员服务很不错！ 不管是大堂还是前台，房间、餐厅，服务人员都非常有礼貌。 早餐也算是丰富了。作为老牌五星级酒店，健身房确实差一些，尤其是健身人员素质太差（这个不能怪酒店）。
    酒店位置还不错，门口就有5号线地铁。', '2024-12-23', 4, '[''房间设施'', ''安静程度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231x12000hd5y20qD08C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235b12000hd6wegvB624_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一如既往的好。作为广州地标酒店，也并不是停步不前，而是一直在进步。服务也有提升，', '一如既往的好。作为广州地标酒店，也并不是停步不前，而是一直在进步。服务也有提升，谢谢小宁和小鱼。床品舒适。早餐比以前好吃了', '2025-03-31', 5, '[''整体满意度'', ''房间设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231912000jg74qanD577_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '过年安排在花园酒店，整个气氛很欢乐。酒店各个部门服务都很热情，在酒店用了早茶，也', '过年安排在花园酒店，整个气氛很欢乐。酒店各个部门服务都很热情，在酒店用了早茶，也吃了年夜饭。新年第一天也看了舞狮。房间设施也很好。交通地铁也方便。', '2025-02-02', 5, '[''整体满意度'', ''房间设施'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0233412000i8ryjk086EA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000i8t39te9E7F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '其实是一家很有特色的酒店，只是酒廊太太太太太拉夸，餐食一般服务更差，严重减分。', '其实是一家很有特色的酒店，只是酒廊太太太太太拉夸，餐食一般服务更差，严重减分。
先说有点：在寸土寸金的广州中心地带能拥有小桥流水的岭南风格园林，甚至还有专门为此准备的导览参观活动，足见花园酒店作为一家白金五星级酒店的实力。而且这家酒店负责房务的叔叔阿姨特别热情亲切，是我在别的酒店没有感受过的。
但是，三天两晚的住宿中，花园酒廊拙劣的服务让我和家人一次次感到震惊：先是第一晚，19时许进入酒廊后是一条非常昏暗的通道，唯一的光源就是桌子上的蓝色小夜灯，等走到中心区域后也没有空余座位，虽然当时有两名服务人员，但是并没有解决座位问题，只是表示只能坐在黑暗的过道区域座位，我们询问是否能将过道区域顶灯打开，服务人员竟然答复“老板不喜欢开灯，所以开不了”，最后我们通知当天外籍值班经理到场交涉，在表达了我们不满以及不开灯可能造成客人受伤等安全问题后，经过十多分钟协调才打开了灯。第二天下午，到酒廊享用下午茶，我母亲想坐在室外区域，询问当日酒廊外籍管理人员后表示户外区域是酒吧（对，酒吧酒廊共用一个区域）客人专属座位，我们便在室内区域落座，但是发现有多波酒廊客人落座户外区域，当时酒廊内客人不多且有三名以上工作人员，均没有对这种行为进行劝阻制止，甚至在酒廊客人是否可以坐在户外的问题上不同服务人员回答都有分歧，而我和母亲只是因为“听*话”就遭到了区别对待，让我们非常恼火。
以上情况，在向酒店值班经理等领导层反馈后，也只是得到了敷衍回答，并没有实际解决问题。
综上，花园酒店给我的感觉就是金絮其外败絮其中，顶着白金五星级酒店的名号，却在本应该是加分项的酒廊，给客人极差的体验。
顺便说一句，酒店酒吧酒廊共用空间，而酒吧并未按照《中华人民共和国未成年人保护法》第五十八条　（营业性酒吧等不适宜未成年人活动场所的经营者，不得允许未成年人进入。经营者应当在显著位置设置未成年人禁入、限入标志；对难以判明是否是未成年人的，应当要求其出示身份证件）规定执行，此情况已向相关部门反映，也请酒店积极整改！', '2025-01-22', 3, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231s12000hzwsavu5CBB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000hzwjuhzADB2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000hzvxnj9B655_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000hzwzqh8C2C3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店超赞，不愧是白金五星，除了前台服务，其它酒店员工都很好。前台基本都板着脸，岭', '酒店超赞，不愧是白金五星，除了前台服务，其它酒店员工都很好。前台基本都板着脸，岭南金卡权益点一点拜一拜，不会主动把权益给你，赠送行政酒廊和早餐等，你提了，会给你加到备注里，不提就没有。', '2025-01-02', 4, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236m12000hjj3qtf29AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000hji5rq590F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000hjijdy86431_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '升级了套房，对着花园瀑布，入住当天等了太久所以送了酒店的欢乐时光，早餐1楼是瀑布', '升级了套房，对着花园瀑布，入住当天等了太久所以送了酒店的欢乐时光，早餐1楼是瀑布餐厅无猪肉非常适合挑食的我，30楼是旋转餐厅，都很有特色，酒店本身自带的花园很舒服。酒店服务很好，感谢热情的carrie小姐姐给我们拍照。空调和马桶年代久远来的时候维修耽误了时间，总体瑕不掩瑜。提一点建议，打电话问酒店要蚊香和晾衣架接线的人说没有，还好奇为啥五星酒店这都不配，但是最后都送过来了，接线员连感觉酒店有啥都不知道', '2025-02-11', 5, '[''景观/朝向'', ''餐饮设施'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235i12000ighceckEC50_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000igh4mzp958E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000iggytz2825D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000ighbvieA6B2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂、餐厅、花园等公共区域环境很好。房间有点儿小，有咖啡机很不错，茶难喝，打扫的', '大堂、餐厅、花园等公共区域环境很好。房间有点儿小，有咖啡机很不错，茶难喝，打扫的非常及时。
服务员及其多，都阳光靓丽，保持微笑服务。
购买的套餐是带行政礼遇、应该安排18-21层的房间。提醒过前台服务员后才看到，可能太忙了吧。
餐食挺好，早餐丰富，行政礼遇的下午茶阳光明媚、欢乐时光餐食比较丰富。', '2024-12-20', 4, '[''餐饮设施'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233312000hb3jtl1CD0D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234d12000hb3czzg8FDF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000hb4pyviEA53_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌五星级酒店，设施不算新，但是干净整洁，服务态度好，酒店大堂金碧辉煌，香气弥漫', '老牌五星级酒店，设施不算新，但是干净整洁，服务态度好，酒店大堂金碧辉煌，香气弥漫，高级感十足，花园瀑布景观无敌，博物馆非常值得一逛，有金庸先生的墨宝。', '2025-02-01', 4, '[''景观/朝向'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231012000i8e0n00E741_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232k12000i8cbfhh3911_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000i8e1o3lEFA8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236k12000i8dsb9k833D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231912000i8dzoum27DA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州老牌五星酒店，新年期间很多庆祝活动，中外游客众多，服务很好，特别是一众酒店前', '广州老牌五星酒店，新年期间很多庆祝活动，中外游客众多，服务很好，特别是一众酒店前台人员，亲切耐心，素质高，很能体现广州人热情好客的人文情怀。', '2025-01-29', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232q12000i4zxz7zE61B_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233412000i4zxdc23830_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233l12000i4zxah38109_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233c12000i4zxpyz28B0_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236012000i4zxpz649AB_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231o12000i4zy732CDC4_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231e12000i4zy8f01206_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233b12000i4zy094E756_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233m12000i4zy2dlC88D_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '寸土尺金的地方，这个房间面积中规中矩', '寸土尺金的地方，这个房间面积中规中矩
标配浴缸占用了空间，但确实也为这次住宿增添色彩，卫生间和淋浴间是分离，但空间很小，有点压抑感。酒廊是最好的体验，如果有机会下次再来尝试其他房型', '2024-12-31', 4, '[''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233w12000hiesw2t4939_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233h12000hiextnn873B_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230t12000hiex0yl581B_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地理位置优越，很近地铁站，附近也有商铺配套设施。住了三晚，不错。送了水果盘，更意', '地理位置优越，很近地铁站，附近也有商铺配套设施。住了三晚，不错。送了水果盘，更意外的是刚好我生日，送了生日蛋糕，真的很惊喜。', '2025-02-13', 4, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235212000ihpbcvf9FE8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000ihp7p031CBB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235012000ihou6ku5975_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店地理位置优越，前台Gillian小姐姐服务很好，唯一不足的就是，房间布局有点', '酒店地理位置优越，前台Gillian小姐姐服务很好，唯一不足的就是，房间布局有点不合理，卫生间，淋浴房共用一扇门，淋浴房和浴缸是一体的，老人和小朋友洗澡爬进爬出不太方便', '2025-01-09', 5, '[''房间设施'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234k12000ho3sj93885D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000ho3s6iw2EED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232n12000ho3wmmm66DF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌的五星酒店，外国客人很多，服务员很热情，这点南方酒店胜出一大截。酒店出门就是', '老牌的五星酒店，外国客人很多，服务员很热情，这点南方酒店胜出一大截。酒店出门就是地铁，工作日入住酒店给升了套间，本身的套餐包含了早餐和夜茶，所以性价比实在太高了。推荐！', '2025-02-03', 5, '[''性价比'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236s12000i9wmjzp3021_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000i9we0573795_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230o12000i9wuyq39E38_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235y12000i9wnvw2438C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000i9wtu3jBDCC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000i9xd5t70FFD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '度假结束了，有时间来好好写点评，看中花园酒店的位置，定了套餐，更看重花园酒店的历', '度假结束了，有时间来好好写点评，看中花园酒店的位置，定了套餐，更看重花园酒店的历史酒店礼宾部John下午的酒店导览对我们这次入住花园酒店是最大的加分，不仅让我们了解了花园酒店的历史更了解了广州作为我国改革开放前沿的窗口的不同，当内地还在继续计划经济的时候，广州已经在吸引外资了，我们的港澳同胞们作为祖国改革开放的坚定拥护者，爱国拳拳之心！花园酒店的花园，瀑布，大锦鲤都让人印象深刻，遗憾的是广州的美食太多，酒店的套餐都没来得及吃，唯一吃了一次早餐一楼是要排队的还是顶楼的比较好！再次感谢John给我们的导览，还有前台Betty的鲜花，给我们的圣诞假期带来了美好的开始！', '2025-01-03', 5, '[''前台服务'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234512000hkooj6aE601_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231v12000hkonnha36C2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234012000hko1mh607DB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234w12000hko1mh8A492_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000hkntxug7CA5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '装修很豪华美丽，外观、花园、大厅都非常漂亮，古典优雅，地段也很好，出行方便，周围', '装修很豪华美丽，外观、花园、大厅都非常漂亮，古典优雅，地段也很好，出行方便，周围吃喝玩乐都很丰富，但是毕竟是老酒店，房间很小，水池、浴室、墙角等角落也能看到发霉发黑，房间阴冷，被子也冰冰的，而且前台办入住非常慢，如果不是商务出行，自家出游的话，这个价位可以定综合水平更舒适的', '2025-01-01', 3, '[''房间设施'', ''前台服务'', ''交通便利性'']', '["[ \"https://dimg04.c-ctrip.com/images/0234112000hixaxjx28BD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235712000hix76rs8B75_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '大堂美丽气派。红棉套房，新装修的，漂亮温馨。居住舒适。前台YOLO小姑娘热情解答', '大堂美丽气派。红棉套房，新装修的，漂亮温馨。居住舒适。前台YOLO小姑娘热情解答各种问题。
涉外酒店??老外很多。感觉对内宾没有对外宾热情??
早餐自助瀑布餐厅人太多了，还没用完餐，桌子就被占领了??周围在施工有点不便。
西餐厅ZONA LIANG 非常热情，一直帮着拍照????', '2024-12-17', 4, '[''前台服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232x12000h95p7rd41C7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000h95mgxf7AC3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000h95am0c8B18_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很大，安静干净，早餐在一楼瀑布餐厅和30楼旋转餐厅，风景不错。前台服务员业务', '房间很大，安静干净，早餐在一楼瀑布餐厅和30楼旋转餐厅，风景不错。前台服务员业务熟悉，态度热情，保安非常主动帮助拿行李。酒店很大，管理到位。', '2025-01-31', 5, '[''整体满意度'', ''前台服务'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230x12000i6jz8vj5F54_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000i6kc5nj5BEA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000i6l0rwe785C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232z12000i6lhpkwD0F0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000i6kzz5196DC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000i6lcdwx05E7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '前两天住红棉很棒，照片是绿央的窗户，我理解不了同一个酒店怎么能脏成这样，房间不同', '前两天住红棉很棒，照片是绿央的窗户，我理解不了同一个酒店怎么能脏成这样，房间不同内部设施有差别我能理解，大过年的窗户怎么能这么脏呢？', '2025-02-01', 4, '[''卫生状况'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236p12000i7jbiiuF052_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '舒适、出入方便，中餐和西餐都是米其林餐厅，出品非常好，服务态度超好，大堂的咖啡厅', '舒适、出入方便，中餐和西餐都是米其林餐厅，出品非常好，服务态度超好，大堂的咖啡厅做的点心也非常棒！所以每次来广州都是首选。', '2025-04-17', 5, '[''餐饮设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235j12000jvf0cv0C9EE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000jvdcnk96F6C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236v12000jve7r5sBB0B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000jvejcakC3C9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000jvf9jra3BB8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间整洁卫生，环境优美。liven服务很好。适合亲子旅行。', '房间整洁卫生，环境优美。liven服务很好。适合亲子旅行。', '2025-04-06', 5, '[''卫生状况'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0231712000jlp19tnBAF6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超预期的好，豪华酒店的调性和标准在线，老酒店有新装修后也非常棒，赞，服务很好，谢', '超预期的好，豪华酒店的调性和标准在线，老酒店有新装修后也非常棒，赞，服务很好，谢谢Mancy的安排。这位置很好，去哪都方便，下次再见', '2025-02-04', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232l12000iayx267FEBF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000iazkf7t8F69_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j12000iayxobtDDF7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很大很干净卫生，在房间可以自己煮咖啡，有两个洗手盆，很方便。服务态度很好，在', '房间很大很干净卫生，在房间可以自己煮咖啡，有两个洗手盆，很方便。服务态度很好，在上下电梯口都有服务员服务，出入酒店门口也有服务员开门，很礼貌，贵宾待遇！餐饮也不错', '2025-01-21', 5, '[''房间设施'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231912000hyuswmjEA48_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000hyv6zkr081C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000hyvs2j991DF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000hyubkcmEA14_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236012000hyukb573BA5_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '到酒店那天，出租车到正门口，没有服务员来开门与拿行李，我们带着孩子自己拿大包小包', '到酒店那天，出租车到正门口，没有服务员来开门与拿行李，我们带着孩子自己拿大包小包进门的。
酒店虽然不是很新，但是维护的很好。我们带小孩，酒店没有床围，我们订的房型大床才1.8米，没办法睡觉，交涉后才给我们升级了房型，但是真正入住是到5、6点才好的。我们吃完饭才回大堂拿了房卡并知道了房号，真的是第一次的体验。
再有希望卫生间可以有马桶冲洗功能，实在是不习惯。另外周边在修马路，房间里还是可以听到修路的噪音。其余都还行，反正挺适合商务的，不适合亲子出行。', '2024-12-09', 4, '[''房间设施'', ''前台服务'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231t12000h4hbrq9A001_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000h4hdkx5C89B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000h4hlnmbE4DF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000h4he3ja3D35_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '位置优越，地铁口出来就是酒店非常方便，赶着过年去的人很多房间还没收拾好，直接送了', '位置优越，地铁口出来就是酒店非常方便，赶着过年去的人很多房间还没收拾好，直接送了两份早餐，酒廊的下午茶也可以随时都能去，好评??', '2025-02-06', 5, '[''交通便利性'', ''餐饮设施'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0235112000icjqne085FA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235g12000icj6jd3A415_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233012000ick7wqa1BA8_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常满意的一次入住，很喜欢酒店的历史年代感，有机会还会考虑入住。酒店早餐也很丰富', '非常满意的一次入住，很喜欢酒店的历史年代感，有机会还会考虑入住。酒店早餐也很丰富，瀑布花园也特别可爱。', '2025-04-17', 5, '[''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231a12000jvql5yx0043_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000jvpzpvzE15E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000jvqpi4n8C1B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000jvqd5w97B00_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000jvpyug672D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236d12000jvouo0aFCEA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000jvpl5flB3FE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000jvpl5fn0698_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000jvqcjve5FCF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '选中这个酒店是看中它的环境非常漂亮。实际入住后，不仅环境漂亮，工作人员服务也很热', '选中这个酒店是看中它的环境非常漂亮。实际入住后，不仅环境漂亮，工作人员服务也很热情。他们会热情的和你打招呼，需要帮助时也会立即上前。', '2025-01-31', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232u12000i6obf5k2195_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000i6p2wkvFFD9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234x12000i6nw2ujDA7A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '20年前第一次出差就住花园酒店，每次来广州都住这里，酒店员工很友好、服务很好??', '20年前第一次出差就住花园酒店，每次来广州都住这里，酒店员工很友好、服务很好??', '2025-03-14', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236h12000j2klcf3E2BB_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231612000j2klcf9222F_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232c12000j2ko2nvF20F_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间和外部看的出年份，也看的出一直不断改进的影子，总体对得起5星，携程的套餐写的', '房间和外部看的出年份，也看的出一直不断改进的影子，总体对得起5星，携程的套餐写的定制早餐也没明确指引，早餐地方太多了。', '2025-02-04', 4, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230612000ib2kfx7AF31_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231g12000ib24mvs009C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000ib20133B71A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '卫生：房间卫生干净整洁', '卫生：房间卫生干净整洁

